3	// Interactive Discord auth flow using a proper bot token (discord.js WebSocket).
4	// This is separate from the existing DISCORD_WEBHOOK_URL one-way notifications.
5	//
6	// When enabled, auth failures post a message with buttons so the user can
7	// authorize Claude from Discord or approve API key fallback, without SSH-ing in.
8	
9	const logger = require('./logger');
10	
11	const INTERACTIVE_AUTH   = (process.env.DISCORD_INTERACTIVE_AUTH || '').toLowerCase() === 'true';
12	const BOT_TOKEN          = process.env.DISCORD_BOT_TOKEN  || '';
13	const CHANNEL_ID         = process.env.DISCORD_CHANNEL_ID || '';
14	const TIMEOUT_MINUTES    = parseInt(process.env.DISCORD_AUTH_TIMEOUT_MINUTES || '5', 10);
15	const TIMEOUT_MS         = TIMEOUT_MINUTES * 60 * 1000;
16	
17	let client = null;
18	let pendingDecision = null;  // { resolve, timeoutId, messageRef }
19	
20	function isEnabled() {
21	  return INTERACTIVE_AUTH && !!client;
22	}
23	
24	// Call once at startup when DISCORD_INTERACTIVE_AUTH=true.
25	// Returns a promise that resolves once the bot is ready (or rejects on bad token).
26	async function init() {
27	  if (!INTERACTIVE_AUTH) return;
28	  if (!BOT_TOKEN)   throw new Error('DISCORD_INTERACTIVE_AUTH=true but DISCORD_BOT_TOKEN is not set');
29	  if (!CHANNEL_ID)  throw new Error('DISCORD_INTERACTIVE_AUTH=true but DISCORD_CHANNEL_ID is not set');
30	
31	  // Lazy-require discord.js so non-interactive mode has zero overhead.
32	  const { Client, GatewayIntentBits } = require('discord.js');
33	
34	  client = new Client({ intents: [GatewayIntentBits.Guilds] });
35	
36	  client.on('interactionCreate', async (interaction) => {
37	    if (!interaction.isButton()) return;
38	    if (!pendingDecision) {
39	      await interaction.reply({ content: 'No pending auth decision.', ephemeral: true }).catch(() => {});
40	      return;
41	    }
42	
43	    const { resolve, timeoutId, messageRef } = pendingDecision;
44	    pendingDecision = null;
45	    clearTimeout(timeoutId);
46	
47	    const id = interaction.customId;
48	    let responseText;
49	
50	    if (id === 'auth-done') {
51	      responseText = '✅ Got it — retrying with subscription…';
52	      await safeUpdate(interaction, responseText, []);
53	      resolve('retry-subscription');
54	    } else if (id === 'auth-api-key') {
55	      responseText = '💰 Using API key for this task.';
56	      await safeUpdate(interaction, responseText, []);
57	      resolve('use-api-key');
58	    } else {
59	      // Unknown button — ignore
60	      await interaction.reply({ content: 'Unknown action.', ephemeral: true }).catch(() => {});
61	      // Put it back
62	      pendingDecision = { resolve, timeoutId, messageRef };
63	    }
64	  });
