  const { EventEmitter } = require('events');

  let fired = false;
  setImmediate(() => { fired = true; });
  expect(fired).toBe(false);

  // yield to let setImmediate fire
  await new Promise(r => setImmediate(r));
  expect(fired).toBe(true);
  jest.useRealTimers();
});
