'use strict';

// Test the exact sleep → retry pattern in isolation
// Does advanceTimersByTimeAsync handle a sleep + async callback chain?

jest.mock('child_process', () => ({ spawn: jest.fn() }));
jest.mock('../../services/bot/src/logger', () => ({ info: jest.fn(), warn: jest.fn(), error: jest.fn() }));

const { EventEmitter } = require('events');
function fakeProc({ exitCode = 0, stdout = '', stderr = '' } = {}) {
  const proc = new EventEmitter();
  proc.stdout = new EventEmitter();
  proc.stderr = new EventEmitter();
  // Use process.nextTick to be 100% sure it's not faked
  process.nextTick(() => {
    if (stdout) proc.stdout.emit('data', Buffer.from(stdout));
    if (stderr) proc.stderr.emit('data', Buffer.from(stderr));
    proc.emit('close', exitCode);
  });
  return proc;
}

afterEach(() => { jest.clearAllMocks(); jest.useRealTimers(); });

it('sleep then async nextTick callback chain works with advanceTimersByTimeAsync', async () => {
  jest.useFakeTimers();

  const spawn = require('child_process').spawn;
  spawn
    .mockReturnValueOnce(fakeProc({ exitCode: 1, stderr: 'rate limit exceeded' }))
    .mockReturnValueOnce(fakeProc({ exitCode: 0, stdout: 'ok output' }));

  let result = null;

  async function runTest() {
    // simulate the pattern: spawn → fail → sleep → respawn → ok
    const { spawn: sp } = require('child_process');

    function doSpawn() {
      return new Promise((resolve) => {
        const proc = sp('cmd', [], {});
        let stdout = '', stderr = '';
        let stdoutLen = 0;
        proc.stdout.on('data', c => { stdout += c.toString(); stdoutLen += c.length; });
        proc.stderr.on('data', c => { stderr += c.toString(); });
        proc.on('close', code => resolve({ ok: code === 0 && stdoutLen > 0, stderr, stdout }));
      });
    }

    const first = await doSpawn();
    if (!first.ok) {
      // sleep 30 min
      await new Promise(r => setTimeout(r, 30 * 60 * 1000));
      const retry = await doSpawn();
      if (retry.ok) {
        result = 'ok';
      }
    }
  }

  const promise = runTest();
